const count = parseInt(env.get('HUB_COUNT') || '0');
if (count === 0) {
    node.error('HUB_COUNT not set or zero');
    return null;
}
const hubs = [];
for (let i = 1; i <= count; i++) {
    hubs.push({
        name: env.get(`HUB_${i}_NAME`) || `Hub ${i}`,
        addr: env.get(`HUB_${i}_ADDR`),
        user: env.get(`HUB_${i}_USER`),
        pass: env.get(`HUB_${i}_PASS`)
    });
}
const msgs = hubs.map((hub, idx) => ({
    payload: hub,
    parts: {
        id: msg._msgid,
        index: idx,
        count: hubs.length,
        type: 'array',
        ch: 0
    }
}));
return [msgs];

const hub = msg.payload;
msg.hub = hub;
msg.method = 'POST';
msg.url = `http://${hub.addr}/login`;
msg.headers = { 'Content-Type': 'application/x-www-form-urlencoded' };
msg.payload = `username=${encodeURIComponent(hub.user)}&password=${encodeURIComponent(hub.pass)}`;
msg.followRedirects = false;
return msg;

// Hubitat login responds with 302 redirect + Set-Cookie
if (msg.statusCode !== 302 && msg.statusCode !== 200) {
    node.error(`Login failed for ${msg.hub.addr}: HTTP ${msg.statusCode}`);
    return null;
}
const raw = msg.headers && msg.headers['set-cookie'];
if (!raw) {
    node.error(`No Set-Cookie after login for ${msg.hub.addr}`);
    return null;
}
const arr = Array.isArray(raw) ? raw : [raw];
msg.hubCookie = arr.map(c => c.split(';')[0]).join('; ');
// Prepare list-backups request
msg.method = 'GET';
msg.url = `http://${msg.hub.addr}:8080/hub2/localBackups`;
msg.headers = { Cookie: msg.hubCookie };
msg.payload = {};
return msg;

let backups;
try {
    backups = typeof msg.payload === 'string' ? JSON.parse(msg.payload) : msg.payload;
} catch(e) {
    node.error(`Parse backups failed for ${msg.hub.addr}: ${e.message}`);
    return null;
}
if (!Array.isArray(backups) || backups.length === 0) {
    node.warn(`No backups on ${msg.hub.addr} — skipping`);
    return null;
}
// API returns objects with a 'name' field — extract filenames, sort, pick newest
const filenames = backups.map(b => (typeof b === 'string') ? b : b.name).filter(Boolean);
const latest = [...filenames].sort().pop();
msg.backupFilename = latest;
msg.method = 'GET';
msg.url = `http://${msg.hub.addr}:8080/hub/backupDB?fileName=${encodeURIComponent(latest)}`;
msg.headers = { Cookie: msg.hubCookie };
msg.payload = {};
return msg;

if (msg.statusCode && msg.statusCode !== 200) {
    node.error(`Download failed for ${msg.hub.addr}: HTTP ${msg.statusCode}`);
    return null;
}
// Construct: YYYY-MM-DD-HHMM-<hubdate>~<version>.lzf
// Hub filename: e.g. 2026-03-26~2.4.4.155.lzf or 2026-03-26~2.4.4.155~shutdown.lzf
const src = msg.backupFilename || '';
const hubDate = (src.match(/^(\d{4}-\d{2}-\d{2})/) || ['','unknown'])[1];
const version = (src.match(/~(\d+\.\d+\.\d+\.\d+)/) || ['','unknown'])[1];
const now = new Date();
const pad = n => String(n).padStart(2, '0');
const ts = `${now.getFullYear()}-${pad(now.getMonth()+1)}-${pad(now.getDate())}-${pad(now.getHours())}${pad(now.getMinutes())}`;
const backupPath = env.get('BACKUP_PATH') || '/backup';
msg.hubDir  = `${backupPath}/${msg.hub.name}`;
msg.filename = `${msg.hubDir}/${ts}-${hubDate}~${version}.lzf`;
// msg.payload is already the binary buffer from http request (ret=bin)
return msg;

const T1 = parseInt(env.get('RETAIN_T1') || '3');
const T2 = parseInt(env.get('RETAIN_T2') || '3');
const T3 = parseInt(env.get('RETAIN_T3') || '3');
const T4 = parseInt(env.get('RETAIN_T4') || '3');
const T5 = parseInt(env.get('RETAIN_T5') || '3');
const MAX = parseInt(env.get('RETAIN_MAX') || '14');

function parseVer(fname) {
    const m = fname.match(/~([^~]+)\.lzf$/);
    if (!m) return null;
    const p = m[1].split('.');
    if (p.length !== 4) return null;
    return { full: m[1],
             patchKey: `${p[0]}.${p[1]}.${p[2]}`,
             minorKey: `${p[0]}.${p[1]}`,
             majorKey: p[0] };
}

const hubDir = msg.hubDir;
let files;
try {
    files = fs.readdirSync(hubDir).filter(f => f.endsWith('.lzf')).sort().reverse();
} catch(e) {
    node.warn(`Cannot read ${hubDir}: ${e.message}`);
    msg.payload = { hub: msg.hub.name, status: 'ok', retained: 1, deleted: 0 };
    return msg;
}

if (files.length === 0) {
    msg.payload = { hub: msg.hub.name, status: 'ok', retained: 0, deleted: 0 };
    return msg;
}

const currentBuild = parseVer(files[0])?.full;
if (!currentBuild) {
    msg.payload = { hub: msg.hub.name, status: 'ok', retained: files.length, deleted: 0 };
    return msg;
}

const keep = new Set();
let t1Count = 0, t3Count = 0, t4Count = 0, t5Count = 0;
const seenBuilds = new Set();
const keptBuilds = new Set();
const seenPatches = new Set();
const seenMinors = new Set();
const seenMajors = new Set();

function markSeen(v) {
    seenPatches.add(v.patchKey);
    seenMinors.add(v.minorKey);
    seenMajors.add(v.majorKey);
}

function tryLower(f, v) {
    if (!seenPatches.has(v.patchKey) && t3Count < T3) {
        t3Count++; keep.add(f); markSeen(v);
    } else if (!seenMinors.has(v.minorKey) && t4Count < T4) {
        t4Count++; keep.add(f); markSeen(v);
    } else if (!seenMajors.has(v.majorKey) && t5Count < T5) {
        t5Count++; keep.add(f); markSeen(v);
    }
}

for (const f of files) {
    const v = parseVer(f);
    if (!v) { keep.add(f); continue; }
    if (v.full === currentBuild) {
        if (t1Count < T1) { keep.add(f); t1Count++; markSeen(v); }
    } else if (!seenBuilds.has(v.full)) {
        seenBuilds.add(v.full);
        if (keptBuilds.size < T2) {
            keptBuilds.add(v.full); keep.add(f); markSeen(v);
        } else {
            tryLower(f, v);
        }
    } else {
        tryLower(f, v);
    }
}

// Hard cap
let keepArr = files.filter(f => keep.has(f));
if (keepArr.length > MAX) {
    const capSet = new Set(keepArr.slice(0, MAX));
    keepArr.forEach(f => { if (!capSet.has(f)) keep.delete(f); });
}

let deleted = 0;
for (const f of files) {
    if (!keep.has(f)) {
        try { fs.unlinkSync(path.join(hubDir, f)); deleted++; }
        catch(e) { node.warn(`Delete ${f}: ${e.message}`); }
    }
}

msg.payload = {
    hub: msg.hub.name,
    status: 'ok',
    filename: path.basename(msg.filename || ''),
    retained: keep.size,
    deleted
};
return msg;

// msg.payload is the array of hub results collected by the join node
const results = Array.isArray(msg.payload) ? msg.payload : [msg.payload];
msg.payload = {
    timestamp: new Date().toISOString(),
    results
};
msg.topic = 'homelab/hubitat/backup/status';
return msg;

