const arr = Array.isArray(raw) ? raw : [raw];
msg.hubCookie = arr.map(c => c.split(';')[0]).join('; ');
// Trigger update check
msg.method = 'GET';
msg.url = `http://${msg.hub.addr}:8080/hub/cloud/checkForUpdate`;
msg.headers = { Cookie: msg.hubCookie };
msg.payload = {};
return msg;

// After checkForUpdate, get hub details
let checkResult;
try {
    checkResult = typeof msg.payload === 'string' ? JSON.parse(msg.payload) : msg.payload;
} catch(e) { checkResult = {}; }
msg.updateCheck = checkResult;
// Now fetch hub details to get current version
msg.method = 'GET';
msg.url = `http://${msg.hub.addr}:8080/hub/details/json`;
msg.headers = { Cookie: msg.hubCookie };
msg.payload = {};
return msg;

let details;
try {
    details = typeof msg.payload === 'string' ? JSON.parse(msg.payload) : msg.payload;
} catch(e) { details = {}; }

const check = msg.updateCheck || {};
// Hub Details returns platformVersion (not version); checkForUpdate status is UPDATE_AVAILABLE
const currentVersion = details.platformVersion || details.version || 'unknown';
const updateAvailable = !!(check.status === 'UPDATE_AVAILABLE' ||
                           (check.version && check.version !== currentVersion));
msg.payload = {
    hub: msg.hub.name,
    addr: msg.hub.addr,
    currentVersion,
    updateAvailable,
    newVersion: check.version || null,
    raw: check
};
return msg;

const results = Array.isArray(msg.payload) ? msg.payload : [msg.payload];
const withUpdates = results.filter(r => r && r.updateAvailable);
msg.payload = {
    timestamp: new Date().toISOString(),
    checked: results.length,
    updatesAvailable: withUpdates.length,
    hubs: results
};
msg.topic = 'homelab/hubitat/update/available';
return msg;

