msg.url = `http://${hub.addr}/login`;
msg.headers = { 'Content-Type': 'application/x-www-form-urlencoded' };
msg.payload = `username=${encodeURIComponent(hub.user)}&password=${encodeURIComponent(hub.pass)}`;
msg.followRedirects = false;
return msg;

if (msg.statusCode !== 302 && msg.statusCode !== 200) {
    node.error(`Login failed for ${msg.hub.addr}: HTTP ${msg.statusCode}`);
    return null;
}
const raw = msg.headers && msg.headers['set-cookie'];
if (!raw) { node.error(`No cookie for ${msg.hub.addr}`); return null; }
const arr = Array.isArray(raw) ? raw : [raw];
msg.hubCookie = arr.map(c => c.split(';')[0]).join('; ');
// Get current version before applying update
msg.method = 'GET';
msg.url = `http://${msg.hub.addr}:8080/hub/details/json`;
msg.headers = { Cookie: msg.hubCookie };
msg.payload = {};
return msg;

let backups;
try { backups = typeof msg.payload === 'string' ? JSON.parse(msg.payload) : msg.payload; }
catch(e) { backups = []; }
if (Array.isArray(backups) && backups.length > 0) {
    const filenames = backups.map(b => (typeof b === 'string') ? b : b.name).filter(Boolean);
    const latest = [...filenames].sort().pop();
    msg.backupFilename = latest;
    msg.method = 'GET';
    msg.url = `http://${msg.hub.addr}:8080/hub/backupDB?fileName=${encodeURIComponent(latest)}`;
    msg.headers = { Cookie: msg.hubCookie };
    msg.payload = {};
} else {
    // No backups available, skip download and go straight to update
    msg.skipBackup = true;
    msg.payload = Buffer.alloc(0);
}
return msg;

// Save pre-update backup (same filename logic as Group A)
if (msg.skipBackup) {
    // No backup to write — point at /dev/null so the file node doesn't error
    msg.filename = '/dev/null';
    msg.payload = Buffer.alloc(0);
} else {
    if (msg.statusCode !== 200) {
        node.error(`Backup download failed for ${msg.hub.addr}: HTTP ${msg.statusCode}`);
        return null;
    }
    const src = msg.backupFilename || '';
    const hubDate = (src.match(/^(\d{4}-\d{2}-\d{2})/) || ['','unknown'])[1];
    const version = (src.match(/~(\d+\.\d+\.\d+\.\d+)/) || ['','unknown'])[1];
    const now = new Date();
    const pad = n => String(n).padStart(2,'0');
    const ts = `${now.getFullYear()}-${pad(now.getMonth()+1)}-${pad(now.getDate())}-${pad(now.getHours())}${pad(now.getMinutes())}`;
    const backupPath = env.get('BACKUP_PATH') || '/backup';
    msg.hubDir  = `${backupPath}/${msg.hub.name}`;
    msg.filename = `${msg.hubDir}/${ts}-${hubDate}~${version}.lzf`;
}
// Prep Hub Details GET — Write Backup passes msg through; http req node picks up msg.url
msg.method = 'GET';
msg.url = `http://${msg.hub.addr}:8080/hub/details/json`;
msg.headers = { Cookie: msg.hubCookie };
return msg;

// Capture firmware version before triggering update
let details;
try { details = typeof msg.payload === 'string' ? JSON.parse(msg.payload) : msg.payload; }
catch(e) { details = {}; }
msg.versionBefore = details.platformVersion || 'unknown';
// Prep updatePlatform request
msg.method = 'GET';
msg.url = `http://${msg.hub.addr}:8080/hub/cloud/updatePlatform`;
msg.headers = { Cookie: msg.hubCookie };
msg.payload = {};
return msg;

// Initialize poll loop counter
msg.pollCount = 0;
msg.pollMax = 40;  // 40 × 30s = 20 min max
msg.hubWentDown = false;  // set true by catch node if ECONNREFUSED during poll
return msg;

// Re-authenticate before every poll — hub session cookie expires on reboot
const hub = msg.hub;
msg.method = 'POST';
msg.url = `http://${hub.addr}/login`;
msg.headers = { 'Content-Type': 'application/x-www-form-urlencoded' };
msg.payload = `username=${encodeURIComponent(hub.user)}&password=${encodeURIComponent(hub.pass)}`;
msg.followRedirects = false;
delete msg.error;
return msg;

// Extract refreshed session cookie and prepare Hub Details request
const setCookie = msg.headers && (msg.headers['set-cookie'] || msg.headers['Set-Cookie']);
if (setCookie) {
    const cookies = Array.isArray(setCookie) ? setCookie : [setCookie];
    msg.hubCookie = cookies.map(c => c.split(';')[0]).join('; ');
}
msg.method = 'GET';
msg.url = `http://${msg.hub.addr}:8080/hub/details/json`;
msg.headers = { Cookie: msg.hubCookie };
msg.payload = {};
return msg;

let details;
try { details = typeof msg.payload === 'string' ? JSON.parse(msg.payload) : msg.payload; }
catch(e) { details = {}; }
msg.pollCount = (msg.pollCount || 0) + 1;
const newVersion = details.platformVersion || '';
const changed = newVersion && newVersion !== msg.versionBefore;
const timedOut = msg.pollCount >= (msg.pollMax || 40);

if (changed) {
    // Done — update applied
    msg.payload = {
        hub: msg.hub.name,
        status: 'updated',
        versionBefore: msg.versionBefore || 'unknown',
        versionAfter: newVersion,
        polls: msg.pollCount
    };
    return [msg, null];  // port 0: done
} else if (timedOut) {
    // 40 polls (20 min) elapsed with no version change — update did not apply.
    msg.payload = {
        hub: msg.hub.name,
        status: 'no_change',
        version: newVersion,
        polls: msg.pollCount
    };
    return [msg, null];  // port 0: done
} else {
    // Not yet — loop back through delay (Prep Login will re-auth next iteration)
    return [null, msg];  // port 1: loop back through delay
}

msg.hubWentDown = true;
msg.pollCount = (msg.pollCount || 0) + 1;
delete msg.error;
if (msg.pollCount >= (msg.pollMax || 40)) {
    msg.payload = {
        hub: msg.hub ? msg.hub.name : 'unknown',
        status: 'timeout',
        error: 'connection refused',
        polls: msg.pollCount
    };
    return [msg, null];  // port 0: exit to Format Result
}
return [null, msg];  // port 1: loop back through delay

msg.payload = {
    timestamp: new Date().toISOString(),
    ...msg.payload
};
msg.topic = 'homelab/hubitat/update/result';
return msg;
